import React from 'react';

function Experience({ data }) {
  if (!data) return null;

  return (
    <section id="experience" className="py-8 md:py-12 bg-white">
      <div className="max-w-7xl mx-auto px-4">
        <p className="text-xs uppercase tracking-widest text-gray-500 font-semibold mb-4">
          Selected Practice
        </p>
        <h2 className="text-5xl font-black text-gray-900 mb-12">Experience</h2>

        <div className="space-y-10">
          {data.map((exp) => (
            <div key={exp.id} className="border-b border-gray-200 pb-10 last:border-0 flex gap-6">
              {/* Icon */}
              {exp.icon && (
                <div className="flex-shrink-0 w-16 h-16 flex items-center justify-center bg-gray-900 text-white rounded-lg text-2xl font-bold">
                  {exp.icon}
                </div>
              )}
              
              {/* Content */}
              <div className="flex-1">
                <h3 className="text-xl font-black text-gray-900 mb-1">
                  {exp.position}
                </h3>
                <p className="text-sm text-gray-600 mb-2">
                  {exp.company} • {exp.period}
                </p>
                <ul className="space-y-2">
                  {exp.description.map((item, idx) => (
                    <li key={idx} className="text-sm text-gray-600 leading-relaxed flex gap-2">
                      <span className="text-gray-400 mt-0.5">+</span>
                      <span>{item}</span>
                    </li>
                  ))}
                </ul>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export default Experience;
